/**
 * Economic Monitor - Nexus Economic Intelligence System
 * 
 * Fetches, stores, and analyzes economic indicators
 * Persists across sessions for longitudinal analysis
 */

import { EconomicStore } from './store';
import { fetchCryptoRates } from './indicators/crypto';
import { fetchMarketIndices } from './indicators/indices';
import type { EconomicSnapshot, CryptoRates, MarketIndices, MonitorConfig } from './types';

export class EconomicMonitor {
  private store: EconomicStore;
  private sessionId: string;
  private config: MonitorConfig;

  constructor(sessionId: string, config?: Partial<MonitorConfig>) {
    this.sessionId = sessionId;
    this.config = {
      dataDir: config?.dataDir || '/home/bootstrap-v17/bootstrap/data/economic',
      maxSnapshots: config?.maxSnapshots || 100,
      sources: {
        crypto: config?.sources?.crypto ?? true,
        indices: config?.sources?.indices ?? true,
        rates: config?.sources?.rates ?? false,
        labor: config?.sources?.labor ?? false,
      },
    };
    this.store = new EconomicStore(this.config);
  }

  async capture(): Promise<EconomicSnapshot> {
    const capturedAt = new Date().toISOString();
    const snapshotId = `snap_${Date.now()}_${this.sessionId.slice(-8)}`;

    console.log(`[EconMonitor] Capturing snapshot ${snapshotId}...`);

    const promises: Promise<unknown>[] = [];
    if (this.config.sources.crypto) {
      promises.push(fetchCryptoRates(this.sessionId));
    }
    if (this.config.sources.indices) {
      promises.push(fetchMarketIndices(this.sessionId));
    }

    const results = await Promise.allSettled(promises);

    let crypto: CryptoRates | undefined;
    let indices: MarketIndices | undefined;
    let resultIdx = 0;

    if (this.config.sources.crypto) {
      const result = results[resultIdx];
      if (result?.status === 'fulfilled') {
        crypto = result.value as CryptoRates;
      }
      resultIdx++;
    }

    if (this.config.sources.indices) {
      const result = results[resultIdx];
      if (result?.status === 'fulfilled') {
        indices = result.value as MarketIndices;
      }
    }

    // Build summary data
    const summaryData: { crypto?: CryptoRates; indices?: MarketIndices } = {};
    if (crypto) {
      summaryData.crypto = crypto;
    }
    if (indices) {
      summaryData.indices = indices;
    }
    const summary = this.generateSummary(summaryData);

    const snapshot: EconomicSnapshot = {
      id: snapshotId,
      capturedAt,
      sessionId: this.sessionId,
      summary,
    };

    if (crypto) {
      snapshot.crypto = crypto;
    }
    if (indices) {
      snapshot.indices = indices;
    }

    this.store.saveSnapshot(snapshot);
    console.log(`[EconMonitor] Snapshot saved: ${snapshotId}`);

    return snapshot;
  }

  private generateSummary(data: { crypto?: CryptoRates; indices?: MarketIndices }): string {
    const parts: string[] = [];

    if (data.crypto) {
      const btcPrice = data.crypto.bitcoin.usd.toLocaleString('en-US', {
        style: 'currency',
        currency: 'USD',
      });
      const ethPrice = data.crypto.ethereum.usd.toLocaleString('en-US', {
        style: 'currency',
        currency: 'USD',
      });
      parts.push(`Bitcoin: ${btcPrice}, Ethereum: ${ethPrice}`);
    }

    if (data.indices?.sp500.value) {
      parts.push(`S&P 500: ${data.indices.sp500.value.toLocaleString()}`);
    }

    if (data.indices?.vix.value) {
      const vixLevel = data.indices.vix.value < 15 ? 'low (complacent)' :
                       data.indices.vix.value > 25 ? 'high (stressed)' : 'moderate';
      parts.push(`VIX: ${data.indices.vix.value.toFixed(2)} (${vixLevel})`);
    }

    return parts.join(' | ') || 'No data captured';
  }

  getLatestSnapshot(): EconomicSnapshot | null {
    return this.store.loadLatestSnapshot();
  }

  getHistory(): EconomicSnapshot[] {
    return this.store.loadAllSnapshots();
  }

  getStats(): ReturnType<EconomicStore['getSnapshotTrends']> {
    return this.store.getSnapshotTrends();
  }

  getChangeSummary(): string {
    const history = this.getHistory();
    if (history.length < 2) {
      return 'Insufficient history for comparison';
    }

    const current = history[history.length - 1];
    const previous = history[history.length - 2];

    if (!current || !previous) {
      return 'Insufficient history for comparison';
    }

    const comparisons: string[] = [];

    if (current.crypto?.bitcoin.usd && previous.crypto?.bitcoin.usd) {
      const change = ((current.crypto.bitcoin.usd - previous.crypto.bitcoin.usd) / 
                     previous.crypto.bitcoin.usd * 100).toFixed(2);
      comparisons.push(`BTC: ${change}%`);
    }

    if (current.crypto?.ethereum.usd && previous.crypto?.ethereum.usd) {
      const change = ((current.crypto.ethereum.usd - previous.crypto.ethereum.usd) / 
                     previous.crypto.ethereum.usd * 100).toFixed(2);
      comparisons.push(`ETH: ${change}%`);
    }

    if (current.indices?.sp500.value && previous.indices?.sp500.value) {
      const change = ((current.indices.sp500.value - previous.indices.sp500.value) / 
                     previous.indices.sp500.value * 100).toFixed(2);
      comparisons.push(`S&P 500: ${change}%`);
    }

    return comparisons.join(', ') || 'No comparable metrics';
  }

  clearHistory(): void {
    this.store.clearAll();
    console.log('[EconMonitor] All historical data cleared');
  }
}

/**
 * Predictive Timing System
 * Nexus Economic Intelligence - Volatility-Aware Session Planning
 */

import type { EconomicSnapshot } from './types';

export type SessionMode = 'flow' | 'cautious' | 'defensive';
export type VolatilityLevel = 'stable' | 'moderate' | 'high';

export const VOLATILITY_THRESHOLDS = {
  STABLE_MAX: 2.0,
  MODERATE_MAX: 4.0,
} as const;

export const MODE_DESCRIPTIONS: Record<SessionMode, {
  label: string;
  description: string;
  permitted: string[];
  restricted: string[];
}> = {
  flow: {
    label: 'Flow Mode',
    description: 'Low volatility environment. Optimal for creative construction.',
    permitted: ['new features', 'system expansion', 'architectural changes', 'exploration'],
    restricted: []
  },
  cautious: {
    label: 'Cautious Mode',
    description: 'Moderate volatility detected. Prioritize maintenance and completion.',
    permitted: ['bug fixes', 'test completion', 'documentation', 'refactoring'],
    restricted: ['new major features', 'border exploration']
  },
  defensive: {
    label: 'Defensive Mode',
    description: 'High volatility environment. Archive and document only.',
    permitted: ['archival', 'documentation', 'status verification', 'backup'],
    restricted: ['new features', 'changes to core systems', 'experimental work']
  }
};

export interface TimingAnalysis {
  mode: SessionMode;
  volatility: VolatilityLevel;
  combinedChange: number;
  btcChange: number;
  ethChange: number;
  recommendation: string;
  confidence: number;
}

export function calculateVolatility(snapshot: EconomicSnapshot): {
  btcChange: number;
  ethChange: number;
  combined: number;
} {
  const btcChange = Math.abs(snapshot.crypto?.bitcoin.change24h ?? 0);
  const ethChange = Math.abs(snapshot.crypto?.ethereum.change24h ?? 0);
  return { btcChange, ethChange, combined: btcChange + ethChange };
}

export function volatilityToMode(volatility: number): VolatilityLevel {
  if (volatility <= VOLATILITY_THRESHOLDS.STABLE_MAX) return 'stable';
  if (volatility <= VOLATILITY_THRESHOLDS.MODERATE_MAX) return 'moderate';
  return 'high';
}

export function levelToMode(level: VolatilityLevel): SessionMode {
  if (level === 'stable') return 'flow';
  if (level === 'moderate') return 'cautious';
  return 'defensive';
}

function generateRecommendation(mode: SessionMode, level: VolatilityLevel): string {
  const desc = MODE_DESCRIPTIONS[mode];
  if (level === 'stable') return `${desc.label}: ${desc.description}`;
  if (level === 'moderate') return `${desc.label}: Prioritize ${desc.permitted.join(', ')}`;
  return `${desc.label}: Only ${desc.permitted.join(', ')} - Avoid ${desc.restricted.join(', ')}`;
}

function calculateConfidence(snapshot: EconomicSnapshot): number {
  const now = new Date().getTime();
  const captured = new Date(snapshot.capturedAt).getTime();
  const minutesSince = (now - captured) / (1000 * 60);

  let confidence = 1.0;
  if (minutesSince > 60) confidence = 0.9;
  if (minutesSince > 180) confidence = 0.7;
  if (minutesSince > 480) confidence = 0.5;

  const hasBtc = snapshot.crypto?.bitcoin?.usd != null;
  const hasEth = snapshot.crypto?.ethereum?.usd != null;
  if (!hasBtc || !hasEth) confidence *= 0.5;

  return confidence;
}

export function analyzeTiming(snapshot: EconomicSnapshot): TimingAnalysis {
  const vol = calculateVolatility(snapshot);
  const level = volatilityToMode(vol.combined);
  const mode = levelToMode(level);

  return {
    mode,
    volatility: level,
    combinedChange: vol.combined,
    btcChange: vol.btcChange,
    ethChange: vol.ethChange,
    recommendation: generateRecommendation(mode, level),
    confidence: calculateConfidence(snapshot)
  };
}

export function formatTimingAnalysis(analysis: TimingAnalysis): string {
  return [
    '═'.repeat(50),
    ' PREDICTIVE TIMING ANALYSIS',
    '═'.repeat(50),
    '',
    `Session Mode: ${MODE_DESCRIPTIONS[analysis.mode].label.toUpperCase()}`,
    `Volatility: ${analysis.volatility.toUpperCase()}`,
    `Combined: ${analysis.combinedChange.toFixed(2)}%`,
    `Confidence: ${(analysis.confidence * 100).toFixed(0)}%`,
    '',
    analysis.recommendation,
  ].join('\n');
}

